/*
 * Aircraft performance (takeoff / landing / cruise) calculator.
 * POH data, the 3D interpolation engine, and the custom-aircraft
 * workflow are ported from AvareX (apps4av/avarex,
 * lib/aircraft/aircraft_performance.dart) to keep behavior consistent.
 * These are approximations for planning; always consult the aircraft POH.
 *
 * Written in ES5 for compatibility with older Android WebViews.
 */

// The performance profile of the currently loaded aircraft (set via
// perfSetAircraftProfile from the aircraft record). null => no custom
// perf data, fall back to a built-in POH matched by ICAO type.
var perfAircraftProfile = null;

// ------------------------------------------------------------------
// Atmospheric helpers (PerformanceCalculator)
// ------------------------------------------------------------------

function perfIsaTemp(pa) {
    return 15.0 - 2.0 * (pa / 1000.0);
}

function perfDensityAltitude(pa, oat) {
    return pa + 120.0 * (oat - perfIsaTemp(pa));
}

function perfDensityAltitudeFromIsaDeviation(pa, isaDev) {
    return pa + 120.0 * isaDev;
}

function perfClamp(v, lo, hi) {
    return Math.max(lo, Math.min(hi, v));
}

// Wind (headwind positive, tailwind negative) and soft-field corrections.
function perfApplyCorrections(base, headwind, hwPct, twPct, softField, sfPct) {
    if (headwind > 0) {
        base *= (1 - headwind * hwPct / 100.0);
    } else if (headwind < 0) {
        base *= (1 + Math.abs(headwind) * twPct / 100.0);
    }
    if (softField) {
        base *= (1 + sfPct / 100.0);
    }
    return base;
}

// ------------------------------------------------------------------
// Built-in 2D POH table interpolation (PerformanceTable)
// ------------------------------------------------------------------

function perfInterpTable(table, pressureAlt, tempC) {
    var pas = table.pa, temps = table.temps, values = table.values;

    var paLowIdx = 0, paHighIdx = 0;
    for (var i = 0; i < pas.length - 1; i++) {
        if (pressureAlt >= pas[i] && pressureAlt <= pas[i + 1]) { paLowIdx = i; paHighIdx = i + 1; break; }
        if (pressureAlt < pas[0]) { paLowIdx = 0; paHighIdx = 0; break; }
        if (pressureAlt > pas[pas.length - 1]) { paLowIdx = pas.length - 1; paHighIdx = pas.length - 1; break; }
    }

    var tLowIdx = 0, tHighIdx = 0;
    for (var j = 0; j < temps.length - 1; j++) {
        if (tempC >= temps[j] && tempC <= temps[j + 1]) { tLowIdx = j; tHighIdx = j + 1; break; }
        if (tempC < temps[0]) { tLowIdx = 0; tHighIdx = 0; break; }
        if (tempC > temps[temps.length - 1]) { tLowIdx = temps.length - 1; tHighIdx = temps.length - 1; break; }
    }

    var paLow = pas[paLowIdx], paHigh = pas[paHighIdx];
    var tLow = temps[tLowIdx], tHigh = temps[tHighIdx];

    var v11 = values[paLowIdx][tLowIdx];
    var v12 = values[paLowIdx][tHighIdx];
    var v21 = values[paHighIdx][tLowIdx];
    var v22 = values[paHighIdx][tHighIdx];

    var paFrac = (paHigh === paLow) ? 0 : (pressureAlt - paLow) / (paHigh - paLow);
    var tFrac = (tHigh === tLow) ? 0 : (tempC - tLow) / (tHigh - tLow);

    var v1 = v11 + (v12 - v11) * tFrac;
    var v2 = v21 + (v22 - v21) * tFrac;
    return v1 + (v2 - v1) * paFrac;
}

// ------------------------------------------------------------------
// Built-in cruise interpolation (CruisePerformanceTable, single temp)
// ------------------------------------------------------------------

function perfCruiseAtPower(entries, altitude, percentPower) {
    var atAlt = [];
    for (var i = 0; i < entries.length; i++) {
        if (entries[i].altitude === altitude) atAlt.push(entries[i]);
    }
    if (atAlt.length === 0) return {ktas: 0, gph: 0};
    atAlt.sort(function (a, b) { return a.percentPower - b.percentPower; });

    var low = null, high = null;
    for (var k = 0; k < atAlt.length - 1; k++) {
        if (percentPower >= atAlt[k].percentPower && percentPower <= atAlt[k + 1].percentPower) {
            low = atAlt[k]; high = atAlt[k + 1]; break;
        }
    }
    if (low === null || high === null) {
        if (percentPower <= atAlt[0].percentPower) { low = atAlt[0]; high = atAlt[0]; }
        else { low = atAlt[atAlt.length - 1]; high = atAlt[atAlt.length - 1]; }
    }
    var frac = (high.percentPower === low.percentPower) ? 0 :
        (percentPower - low.percentPower) / (high.percentPower - low.percentPower);
    return {
        ktas: low.ktas + (high.ktas - low.ktas) * frac,
        gph: low.gph + (high.gph - low.gph) * frac
    };
}

function perfCruise(ac, altitude, percentPower) {
    var entries = ac.cruise;
    if (!entries || entries.length === 0) return {ktas: 0, gph: 0};

    var alts = [];
    for (var i = 0; i < entries.length; i++) {
        if (alts.indexOf(entries[i].altitude) === -1) alts.push(entries[i].altitude);
    }
    alts.sort(function (a, b) { return a - b; });

    var altLow = alts[0], altHigh = alts[alts.length - 1];
    for (var j = 0; j < alts.length - 1; j++) {
        if (altitude >= alts[j] && altitude <= alts[j + 1]) { altLow = alts[j]; altHigh = alts[j + 1]; break; }
    }
    if (altitude < alts[0]) { altLow = alts[0]; altHigh = alts[0]; }
    if (altitude > alts[alts.length - 1]) { altLow = alts[alts.length - 1]; altHigh = alts[alts.length - 1]; }

    var lowR = perfCruiseAtPower(entries, altLow, percentPower);
    var highR = perfCruiseAtPower(entries, altHigh, percentPower);
    var altFrac = (altHigh === altLow) ? 0 : (altitude - altLow) / (altHigh - altLow);

    return {
        ktas: lowR.ktas + (highR.ktas - lowR.ktas) * altFrac,
        gph: Math.round((lowR.gph + (highR.gph - lowR.gph) * altFrac) * 10) / 10.0
    };
}

// ==================================================================
// Interpolator3D - custom-aircraft POH interpolation (ported from
// AvareX). Natural cubic-spline tensor product on a completed grid,
// with polynomial-fit and inverse-distance-weighted fallbacks.
// ==================================================================

function i3_uniqueSorted(arr) {
    var out = [];
    for (var i = 0; i < arr.length; i++) {
        if (out.indexOf(arr[i]) === -1) out.push(arr[i]);
    }
    out.sort(function (a, b) { return a - b; });
    return out;
}

// 1D natural cubic spline through all points; linear extrapolation outside range.
function i3_interp1d(xs, ys, x) {
    var n = xs.length;
    if (n === 1) return ys[0];
    if (n === 2) {
        var dx = xs[1] - xs[0];
        if (dx === 0) return ys[0];
        return ys[0] + (x - xs[0]) * (ys[1] - ys[0]) / dx;
    }

    var h = new Array(n - 1);
    for (var k = 0; k < n - 1; k++) h[k] = xs[k + 1] - xs[k];

    var innerN = n - 2;
    var diag = new Array(innerN), sup = new Array(innerN), rhs = new Array(innerN);
    for (var k2 = 0; k2 < innerN; k2++) {
        diag[k2] = 2 * (h[k2] + h[k2 + 1]);
        sup[k2] = (k2 < innerN - 1) ? h[k2 + 1] : 0;
        rhs[k2] = 6 * ((ys[k2 + 2] - ys[k2 + 1]) / h[k2 + 1] - (ys[k2 + 1] - ys[k2]) / h[k2]);
    }
    for (var k3 = 1; k3 < innerN; k3++) {
        var w = h[k3] / diag[k3 - 1];
        diag[k3] -= w * sup[k3 - 1];
        rhs[k3] -= w * rhs[k3 - 1];
    }
    var m = new Array(n);
    for (var z = 0; z < n; z++) m[z] = 0;
    m[n - 2] = rhs[innerN - 1] / diag[innerN - 1];
    for (var k4 = innerN - 2; k4 >= 0; k4--) {
        m[k4 + 1] = (rhs[k4] - sup[k4] * m[k4 + 2]) / diag[k4];
    }

    if (x <= xs[0]) {
        var slope0 = (ys[1] - ys[0]) / h[0] - h[0] * (2 * m[0] + m[1]) / 6;
        return ys[0] + (x - xs[0]) * slope0;
    }
    if (x >= xs[n - 1]) {
        var slopeN = (ys[n - 1] - ys[n - 2]) / h[n - 2] + h[n - 2] * (m[n - 2] + 2 * m[n - 1]) / 6;
        return ys[n - 1] + (x - xs[n - 1]) * slopeN;
    }

    var i = 0;
    for (var k5 = 0; k5 < n - 1; k5++) {
        if (x >= xs[k5] && x <= xs[k5 + 1]) { i = k5; break; }
    }
    var hh = h[i];
    var a1 = xs[i + 1] - x;
    var a2 = x - xs[i];
    return m[i] * a1 * a1 * a1 / (6 * hh) +
        m[i + 1] * a2 * a2 * a2 / (6 * hh) +
        (ys[i] / hh - m[i] * hh / 6) * a1 +
        (ys[i + 1] / hh - m[i + 1] * hh / 6) * a2;
}

function i3_intPow(v, n) {
    if (n === 0) return 1;
    var r = 1, base = v, e = n;
    while (e > 0) {
        if ((e & 1) === 1) r *= base;
        e >>= 1;
        if (e > 0) base *= base;
    }
    return r;
}

function i3_gaussSolve(a, b) {
    var n = a.length;
    var m = [];
    for (var i = 0; i < n; i++) {
        var row = a[i].slice();
        row.push(b[i]);
        m.push(row);
    }
    for (var c = 0; c < n; c++) {
        var pivot = c, pivotMag = Math.abs(m[c][c]);
        for (var k = c + 1; k < n; k++) {
            var mag = Math.abs(m[k][c]);
            if (mag > pivotMag) { pivot = k; pivotMag = mag; }
        }
        if (pivotMag < 1e-12) return null;
        if (pivot !== c) { var tmp = m[c]; m[c] = m[pivot]; m[pivot] = tmp; }
        var pivotVal = m[c][c];
        for (var k2 = c + 1; k2 < n; k2++) {
            var factor = m[k2][c] / pivotVal;
            if (factor === 0) continue;
            for (var j = c; j <= n; j++) m[k2][j] -= factor * m[c][j];
        }
    }
    var x = new Array(n);
    for (var i2 = n - 1; i2 >= 0; i2--) {
        var s = m[i2][n];
        for (var j2 = i2 + 1; j2 < n; j2++) s -= m[i2][j2] * x[j2];
        x[i2] = s / m[i2][i2];
    }
    return x;
}

function i3_polyFit2D(points, targetX, targetY, degree) {
    var n = points.length;
    var numTerms = ((degree + 1) * (degree + 2)) >> 1;
    if (n < numTerms) return null;

    var meanX = 0, meanY = 0, p;
    for (var i = 0; i < n; i++) { meanX += points[i][0]; meanY += points[i][1]; }
    meanX /= n; meanY /= n;

    var scaleX = 0, scaleY = 0;
    for (var i2 = 0; i2 < n; i2++) {
        var ddx = Math.abs(points[i2][0] - meanX);
        var ddy = Math.abs(points[i2][1] - meanY);
        if (ddx > scaleX) scaleX = ddx;
        if (ddy > scaleY) scaleY = ddy;
    }
    if (scaleX < 1e-9) scaleX = 1;
    if (scaleY < 1e-9) scaleY = 1;

    var a = [], b = [];
    for (var r = 0; r < n; r++) {
        var dx = (points[r][0] - meanX) / scaleX;
        var dy = (points[r][1] - meanY) / scaleY;
        var rowA = [];
        for (var d = 0; d <= degree; d++) {
            for (var kk = 0; kk <= d; kk++) rowA.push(i3_intPow(dx, d - kk) * i3_intPow(dy, kk));
        }
        a.push(rowA);
        b.push(points[r][2]);
    }

    var ata = [], atb = [];
    for (var ii = 0; ii < numTerms; ii++) { ata.push(new Array(numTerms)); atb.push(0); }
    for (var iii = 0; iii < numTerms; iii++) {
        for (var jjj = iii; jjj < numTerms; jjj++) {
            var s = 0;
            for (var k = 0; k < n; k++) s += a[k][iii] * a[k][jjj];
            ata[iii][jjj] = s; ata[jjj][iii] = s;
        }
        var s2 = 0;
        for (var k2 = 0; k2 < n; k2++) s2 += a[k2][iii] * b[k2];
        atb[iii] = s2;
    }
    for (var q = 0; q < numTerms; q++) ata[q][q] += 1e-9;

    var coeffs = i3_gaussSolve(ata, atb);
    if (coeffs === null) return null;

    var tdx = (targetX - meanX) / scaleX;
    var tdy = (targetY - meanY) / scaleY;
    var result = 0, t = 0;
    for (var d2 = 0; d2 <= degree; d2++) {
        for (var k3 = 0; k3 <= d2; k3++) result += coeffs[t++] * i3_intPow(tdx, d2 - k3) * i3_intPow(tdy, k3);
    }
    return result;
}

function i3_idw(points, targetDa, weight) {
    var totalW = 0, weightedSum = 0;
    for (var i = 0; i < points.length; i++) {
        var daDist = Math.abs(points[i][0] - targetDa) / 1000.0;
        var wDist = Math.abs(points[i][1] - weight) / 500.0;
        var dist = Math.sqrt(daDist * daDist + wDist * wDist);
        if (dist < 0.001) dist = 0.001;
        var w = 1 / (dist * dist);
        weightedSum += points[i][2] * w;
        totalW += w;
    }
    return totalW > 0 ? weightedSum / totalW : points[0][2];
}

// Gridded tensor-product spline on (altitude, temp, weight). Returns null if not griddable.
function i3_interpOnGrid(entries, alt, temp, weight) {
    var alts = i3_uniqueSorted(entries.map(function (e) { return e.altitude; }));
    var temps = i3_uniqueSorted(entries.map(function (e) { return e.temp; }));
    var weights = i3_uniqueSorted(entries.map(function (e) { return e.weight; }));

    if (alts.length < 2 && temps.length < 2 && weights.length < 2) return null;

    var grid = [];
    for (var ai0 = 0; ai0 < alts.length; ai0++) {
        var plane = [];
        for (var ti0 = 0; ti0 < temps.length; ti0++) {
            var col = [];
            for (var wi0 = 0; wi0 < weights.length; wi0++) col.push(null);
            plane.push(col);
        }
        grid.push(plane);
    }
    for (var e = 0; e < entries.length; e++) {
        var ai = alts.indexOf(entries[e].altitude);
        var ti = temps.indexOf(entries[e].temp);
        var wi = weights.indexOf(entries[e].weight);
        if (ai < 0 || ti < 0 || wi < 0) return null;
        if (grid[ai][ti][wi] === null) grid[ai][ti][wi] = entries[e].value;
    }

    function countMissing() {
        var c = 0;
        for (var a = 0; a < alts.length; a++)
            for (var t = 0; t < temps.length; t++)
                for (var w = 0; w < weights.length; w++)
                    if (grid[a][t][w] === null) c++;
        return c;
    }

    var missing = countMissing();
    while (missing > 0) {
        var progress = false;
        for (var a2 = 0; a2 < alts.length; a2++) {
            for (var t2 = 0; t2 < temps.length; t2++) {
                for (var w2 = 0; w2 < weights.length; w2++) {
                    if (grid[a2][t2][w2] !== null) continue;
                    var estimates = [];

                    var aXs = [], aYs = [];
                    for (var k = 0; k < alts.length; k++) {
                        var v = grid[k][t2][w2];
                        if (v !== null) { aXs.push(alts[k]); aYs.push(v); }
                    }
                    if (aXs.length >= 2) estimates.push(i3_interp1d(aXs, aYs, alts[a2]));

                    var tXs = [], tYs = [];
                    for (var k2 = 0; k2 < temps.length; k2++) {
                        var v2 = grid[a2][k2][w2];
                        if (v2 !== null) { tXs.push(temps[k2]); tYs.push(v2); }
                    }
                    if (tXs.length >= 2) estimates.push(i3_interp1d(tXs, tYs, temps[t2]));

                    var wXs = [], wYs = [];
                    for (var k3 = 0; k3 < weights.length; k3++) {
                        var v3 = grid[a2][t2][k3];
                        if (v3 !== null) { wXs.push(weights[k3]); wYs.push(v3); }
                    }
                    if (wXs.length >= 2) estimates.push(i3_interp1d(wXs, wYs, weights[w2]));

                    if (estimates.length > 0) {
                        var sum = 0;
                        for (var s = 0; s < estimates.length; s++) sum += estimates[s];
                        grid[a2][t2][w2] = sum / estimates.length;
                        progress = true;
                    }
                }
            }
        }
        var newMissing = countMissing();
        if (!progress || newMissing === missing) {
            if (newMissing > 0) return null;
            break;
        }
        missing = newMissing;
    }

    var alongAlt = [];
    for (var a3 = 0; a3 < alts.length; a3++) {
        var alongTemp = [];
        for (var t3 = 0; t3 < temps.length; t3++) {
            var wColumn = [];
            for (var wi2 = 0; wi2 < weights.length; wi2++) wColumn.push(grid[a3][t3][wi2]);
            alongTemp.push(i3_interp1d(weights, wColumn, weight));
        }
        alongAlt.push(i3_interp1d(temps, alongTemp, temp));
    }
    return i3_interp1d(alts, alongAlt, alt);
}

function i3_scatteredPolyDA(entries, alt, temp, weight) {
    var targetDa = perfDensityAltitude(alt, temp);
    var points = entries.map(function (e) {
        return [perfDensityAltitude(e.altitude, e.temp), e.weight, e.value];
    });

    for (var i = 0; i < points.length; i++) {
        if (Math.abs(points[i][0] - targetDa) < 1e-6 && Math.abs(points[i][1] - weight) < 1e-6) return points[i][2];
    }

    var uniqueDa = i3_uniqueSorted(points.map(function (p) { return p[0]; }));
    var uniqueW = i3_uniqueSorted(points.map(function (p) { return p[1]; }));

    var degree;
    if (entries.length >= 10 && uniqueDa.length >= 4 && uniqueW.length >= 3) degree = 3;
    else if (entries.length >= 6 && uniqueDa.length >= 3 && uniqueW.length >= 2) degree = 2;
    else degree = 1;

    var fitted = i3_polyFit2D(points, targetDa, weight, degree);
    while (fitted === null && degree > 1) { degree--; fitted = i3_polyFit2D(points, targetDa, weight, degree); }
    if (fitted === null) return i3_idw(points, targetDa, weight);

    var minV = points[0][2], maxV = points[0][2];
    for (var j = 0; j < points.length; j++) {
        if (points[j][2] < minV) minV = points[j][2];
        if (points[j][2] > maxV) maxV = points[j][2];
    }
    var pad = Math.abs(maxV - minV) * 0.25;
    return perfClamp(fitted, minV - pad, maxV + pad);
}

function i3_interpolatePerformance(entries, alt, temp, weight) {
    if (entries.length === 0) return 0;
    if (entries.length === 1) return entries[0].value;
    var gridded = i3_interpOnGrid(entries, alt, temp, weight);
    if (gridded !== null) return gridded;
    return i3_scatteredPolyDA(entries, alt, temp, weight);
}

function i3_cruiseOnGrid(entries, alt, temp, power) {
    var alts = i3_uniqueSorted(entries.map(function (e) { return e.altitude; }));
    var temps = i3_uniqueSorted(entries.map(function (e) { return e.temp; }));
    var powers = i3_uniqueSorted(entries.map(function (e) { return e.powerPercent; }));

    if (alts.length < 2 && temps.length < 2 && powers.length < 2) return null;

    function mk3() {
        var g = [];
        for (var a = 0; a < alts.length; a++) {
            var pl = [];
            for (var t = 0; t < temps.length; t++) {
                var c = [];
                for (var p = 0; p < powers.length; p++) c.push(null);
                pl.push(c);
            }
            g.push(pl);
        }
        return g;
    }
    var ktasGrid = mk3(), gphGrid = mk3();

    for (var e = 0; e < entries.length; e++) {
        var ai = alts.indexOf(entries[e].altitude);
        var ti = temps.indexOf(entries[e].temp);
        var pi = powers.indexOf(entries[e].powerPercent);
        if (ai < 0 || ti < 0 || pi < 0) return null;
        if (ktasGrid[ai][ti][pi] === null) { ktasGrid[ai][ti][pi] = entries[e].ktas; gphGrid[ai][ti][pi] = entries[e].gph; }
    }

    function countMissing() {
        var c = 0;
        for (var a = 0; a < alts.length; a++)
            for (var t = 0; t < temps.length; t++)
                for (var p = 0; p < powers.length; p++)
                    if (ktasGrid[a][t][p] === null) c++;
        return c;
    }

    var missing = countMissing();
    while (missing > 0) {
        var progress = false;
        for (var a2 = 0; a2 < alts.length; a2++) {
            for (var t2 = 0; t2 < temps.length; t2++) {
                for (var p2 = 0; p2 < powers.length; p2++) {
                    if (ktasGrid[a2][t2][p2] !== null) continue;
                    var kEst = [], gEst = [];

                    var aXs = [], aK = [], aG = [];
                    for (var k = 0; k < alts.length; k++) {
                        var kv = ktasGrid[k][t2][p2];
                        if (kv !== null) { aXs.push(alts[k]); aK.push(kv); aG.push(gphGrid[k][t2][p2]); }
                    }
                    if (aXs.length >= 2) { kEst.push(i3_interp1d(aXs, aK, alts[a2])); gEst.push(i3_interp1d(aXs, aG, alts[a2])); }

                    var tXs = [], tK = [], tG = [];
                    for (var k2 = 0; k2 < temps.length; k2++) {
                        var kv2 = ktasGrid[a2][k2][p2];
                        if (kv2 !== null) { tXs.push(temps[k2]); tK.push(kv2); tG.push(gphGrid[a2][k2][p2]); }
                    }
                    if (tXs.length >= 2) { kEst.push(i3_interp1d(tXs, tK, temps[t2])); gEst.push(i3_interp1d(tXs, tG, temps[t2])); }

                    var pXs = [], pK = [], pG = [];
                    for (var k3 = 0; k3 < powers.length; k3++) {
                        var kv3 = ktasGrid[a2][t2][k3];
                        if (kv3 !== null) { pXs.push(powers[k3]); pK.push(kv3); pG.push(gphGrid[a2][t2][k3]); }
                    }
                    if (pXs.length >= 2) { kEst.push(i3_interp1d(pXs, pK, powers[p2])); gEst.push(i3_interp1d(pXs, pG, powers[p2])); }

                    if (kEst.length > 0) {
                        var ks = 0, gs = 0;
                        for (var s = 0; s < kEst.length; s++) ks += kEst[s];
                        for (var s2 = 0; s2 < gEst.length; s2++) gs += gEst[s2];
                        ktasGrid[a2][t2][p2] = ks / kEst.length;
                        gphGrid[a2][t2][p2] = gs / gEst.length;
                        progress = true;
                    }
                }
            }
        }
        var newMissing = countMissing();
        if (!progress || newMissing === missing) {
            if (newMissing > 0) return null;
            break;
        }
        missing = newMissing;
    }

    var alongAltK = [], alongAltG = [];
    for (var a3 = 0; a3 < alts.length; a3++) {
        var alongTempK = [], alongTempG = [];
        for (var t3 = 0; t3 < temps.length; t3++) {
            var kCol = [], gCol = [];
            for (var pi2 = 0; pi2 < powers.length; pi2++) { kCol.push(ktasGrid[a3][t3][pi2]); gCol.push(gphGrid[a3][t3][pi2]); }
            alongTempK.push(i3_interp1d(powers, kCol, power));
            alongTempG.push(i3_interp1d(powers, gCol, power));
        }
        alongAltK.push(i3_interp1d(temps, alongTempK, temp));
        alongAltG.push(i3_interp1d(temps, alongTempG, temp));
    }
    return { ktas: i3_interp1d(alts, alongAltK, alt), gph: i3_interp1d(alts, alongAltG, alt) };
}

function i3_cruiseScattered(entries, alt, temp, power) {
    var totalW = 0, ktasSum = 0, gphSum = 0;
    for (var i = 0; i < entries.length; i++) {
        var altDist = Math.abs(entries[i].altitude - alt) / 1000;
        var tempDist = Math.abs(entries[i].temp - temp) / 10;
        var powerDist = Math.abs(entries[i].powerPercent - power) / 10;
        var dist = Math.sqrt(altDist * altDist + tempDist * tempDist + powerDist * powerDist);
        if (dist < 0.001) dist = 0.001;
        var w = 1 / (dist * dist);
        ktasSum += entries[i].ktas * w;
        gphSum += entries[i].gph * w;
        totalW += w;
    }
    if (totalW > 0) return { ktas: ktasSum / totalW, gph: gphSum / totalW };
    return { ktas: entries[0].ktas, gph: entries[0].gph };
}

function i3_interpolateCruise(entries, alt, temp, power) {
    if (entries.length === 0) return { ktas: 0, gph: 0 };
    if (entries.length === 1) return { ktas: entries[0].ktas, gph: entries[0].gph };

    var targetDa = perfDensityAltitudeFromIsaDeviation(alt, temp);
    var daEntries = entries.map(function (e) {
        return {
            altitude: perfDensityAltitudeFromIsaDeviation(e.altitude, e.temp),
            temp: 0, powerPercent: e.powerPercent, ktas: e.ktas, gph: e.gph
        };
    });

    var gridded = i3_cruiseOnGrid(daEntries, targetDa, 0, power);
    if (gridded !== null) return gridded;
    return i3_cruiseScattered(daEntries, targetDa, 0, power);
}

// ==================================================================
// Custom aircraft distance calculation (raw 3D entries + corrections)
// ==================================================================

function perfDefault(v, d) { return (v === undefined || v === null || isNaN(v)) ? d : v; }

// side = 'takeoff' | 'landing'; kind = 'roll' | 'over50'
function perfCustomDistance(profile, side, kind, pa, temp, weight, wind, soft) {
    var block = (side === 'takeoff') ? profile.takeoff : profile.landing;
    if (!block || !block.entries || block.entries.length === 0) return 0;
    var valueKey = (kind === 'roll') ? 'groundRoll' : 'over50ft';
    var entries = block.entries.map(function (e) {
        return { altitude: e.altitude, temp: e.temp, weight: e.weight, value: e[valueKey] };
    });
    var base = i3_interpolatePerformance(entries, pa, temp, weight);
    var hwPct = perfDefault(block.headwindPct, 1.5);
    var twPct = perfDefault(block.tailwindPct, 10.0);
    var sfPct = perfDefault(block.softFieldPct, side === 'takeoff' ? 15.0 : 20.0);
    base = perfApplyCorrections(base, wind, hwPct, twPct, soft, sfPct);
    var lo, hi;
    if (side === 'takeoff') { lo = (kind === 'roll') ? 100 : 200; hi = (kind === 'roll') ? 10000 : 15000; }
    else { lo = (kind === 'roll') ? 100 : 200; hi = (kind === 'roll') ? 8000 : 12000; }
    return perfClamp(base, lo, hi);
}

// ==================================================================
// UI
// ==================================================================

function perfNum(id, dflt) {
    var el = document.getElementById(id);
    if (!el) return dflt;
    var v = parseFloat(el.value);
    return isNaN(v) ? dflt : v;
}

function perfBuiltinByIcao(icao) {
    if (!icao) return null;
    for (var i = 0; i < PERF_AIRCRAFT.length; i++) {
        if (PERF_AIRCRAFT[i].icao.toLowerCase() === icao.toLowerCase()) return PERF_AIRCRAFT[i];
    }
    return null;
}

// The type (ICAO designator) and tail of the currently loaded aircraft,
// read straight from the Aircraft profile form.
function perfLoadedType() {
    var el = document.getElementById("icaoAircraftTypeInput");
    return el ? el.value : "";
}
function perfLoadedName() {
    var el = document.getElementById("icaoAircraftIdInput");
    return (el && el.value) ? el.value : "Aircraft";
}

function perfHasProfileData() {
    var p = perfAircraftProfile;
    return !!(p && p.takeoff && p.takeoff.entries && p.takeoff.entries.length);
}

// Resolve the performance source for the CURRENTLY LOADED aircraft.
// 1) this aircraft's own perf profile (if it has data), else
// 2) a built-in POH matched by the aircraft's ICAO type, else
// 3) the C172 built-in as a last-resort default.
// Returns {type:'custom'|'builtin', ac:object, maxGross, usableFuel}
function perfResolve() {
    if (perfHasProfileData()) {
        var p = perfAircraftProfile;
        return { type: "custom", ac: p, maxGross: p.maxGross, usableFuel: p.usableFuel };
    }
    var b = perfBuiltinByIcao(perfLoadedType()) || PERF_AIRCRAFT[1];
    return { type: "builtin", ac: b, maxGross: b.maxGross, usableFuel: b.usableFuel };
}

function perfPopulateTemplates() {
    var sel = document.getElementById("perf_template");
    if (!sel) return;
    var html = "";
    for (var i = 0; i < PERF_AIRCRAFT.length; i++) {
        html += '<option value="' + i + '">' + PERF_AIRCRAFT[i].name + '</option>';
    }
    sel.innerHTML = html;
    sel.value = 1;
}

// Recompute the whole Perf tab from the loaded aircraft. Called after the
// aircraft (and thus its perf) changes.
function perfRefresh() {
    var sel = perfResolve();
    document.getElementById("perf_to_weight").value = Math.round(sel.maxGross);
    document.getElementById("perf_ld_weight").value = Math.round(sel.maxGross * 0.9);
    var info = document.getElementById("perf_ac_info");
    if (info) {
        var src = (sel.type === "custom")
            ? "this aircraft's saved performance"
            : ("built-in POH for " + sel.ac.name);
        info.innerHTML = "<b>" + perfLoadedName() + "</b> \u2014 using " + src +
            ".<br>Max gross " + Math.round(sel.maxGross) + " lb, usable fuel " + sel.usableFuel + " gal.";
    }
    perfCalcTakeoff();
    perfCalcLanding();
    perfCalcCruise();
}

// ------------------------------------------------------------------
// Per-aircraft perf: load into the tab / read back for saving
// ------------------------------------------------------------------

// Load the perf that belongs to the loaded aircraft. json may be "" (no
// data). Also seeds the editor so the user can start from this aircraft's
// data or a template.
function perfSetAircraftProfile(json) {
    perfAircraftProfile = null;
    if (json && json.length > 0) {
        try {
            var obj = JSON.parse(json);
            if (obj && obj.name) perfAircraftProfile = obj;
        } catch (e) { perfAircraftProfile = null; }
    }
    if (perfHasProfileData()) {
        perfLoadEditorFromProfile(perfAircraftProfile);
    } else {
        perfLoadEditorFromTemplateForType(perfLoadedType());
    }
    perfRefresh();
}

// JSON for the loaded aircraft's perf (for embedding in the aircraft
// record). "" when the aircraft has no perf data.
function perfGetCurrentProfileJson() {
    return perfHasProfileData() ? JSON.stringify(perfAircraftProfile) : "";
}

function perfCalcTakeoff() {
    var sel = perfResolve();
    var pa = perfNum("perf_to_pa", 0);
    var temp = perfNum("perf_to_temp", 15);
    var weight = perfNum("perf_to_weight", sel.maxGross);
    var wind = perfNum("perf_to_wind", 0);
    var soft = document.getElementById("perf_to_soft").checked;
    var roll, d50;

    if (sel.type === "custom" && sel.ac.takeoff && sel.ac.takeoff.entries && sel.ac.takeoff.entries.length) {
        roll = perfCustomDistance(sel.ac, "takeoff", "roll", pa, temp, weight, wind, soft);
        d50 = perfCustomDistance(sel.ac, "takeoff", "over50", pa, temp, weight, wind, soft);
    } else {
        var ac = (sel.type === "builtin") ? sel.ac : perfBuiltinByIcao(sel.ac.icao) || PERF_AIRCRAFT[1];
        roll = perfInterpTable(ac.takeoffRoll, pa, temp) * Math.pow(weight / ac.maxGross, 2);
        roll = perfClamp(perfApplyCorrections(roll, wind, 1.5, 10.0, soft, 15.0), 100, 10000);
        d50 = perfInterpTable(ac.takeoff50, pa, temp) * Math.pow(weight / ac.maxGross, 2);
        d50 = perfClamp(perfApplyCorrections(d50, wind, 1.5, 10.0, soft, 15.0), 200, 15000);
    }

    document.getElementById("perf_to_roll").textContent = Math.round(roll) + " ft";
    document.getElementById("perf_to_50out").textContent = Math.round(d50) + " ft";
    document.getElementById("perf_to_da").textContent = Math.round(perfDensityAltitude(pa, temp)) + " ft";
}

function perfCalcLanding() {
    var sel = perfResolve();
    var pa = perfNum("perf_ld_pa", 0);
    var temp = perfNum("perf_ld_temp", 15);
    var weight = perfNum("perf_ld_weight", sel.maxGross * 0.9);
    var wind = perfNum("perf_ld_wind", 0);
    var soft = document.getElementById("perf_ld_soft").checked;
    var roll, d50;

    if (sel.type === "custom" && sel.ac.landing && sel.ac.landing.entries && sel.ac.landing.entries.length) {
        roll = perfCustomDistance(sel.ac, "landing", "roll", pa, temp, weight, wind, soft);
        d50 = perfCustomDistance(sel.ac, "landing", "over50", pa, temp, weight, wind, soft);
    } else {
        var ac = (sel.type === "builtin") ? sel.ac : perfBuiltinByIcao(sel.ac.icao) || PERF_AIRCRAFT[1];
        roll = perfInterpTable(ac.landingRoll, pa, temp) * (weight / ac.maxGross);
        roll = perfClamp(perfApplyCorrections(roll, wind, 1.5, 10.0, soft, 20.0), 100, 8000);
        d50 = perfInterpTable(ac.landing50, pa, temp) * (weight / ac.maxGross);
        d50 = perfClamp(perfApplyCorrections(d50, wind, 1.5, 10.0, soft, 20.0), 200, 12000);
    }

    document.getElementById("perf_ld_roll").textContent = Math.round(roll) + " ft";
    document.getElementById("perf_ld_50out").textContent = Math.round(d50) + " ft";
    document.getElementById("perf_ld_da").textContent = Math.round(perfDensityAltitude(pa, temp)) + " ft";
}

function perfCalcCruise() {
    var sel = perfResolve();
    var alt = perfNum("perf_cr_alt", 8000);
    var isa = perfNum("perf_cr_isa", 0);
    var power = perfNum("perf_cr_power", 65);
    var r;

    if (sel.type === "custom" && sel.ac.cruise && sel.ac.cruise.length) {
        var raw = i3_interpolateCruise(sel.ac.cruise, alt, isa, power);
        r = { ktas: raw.ktas, gph: Math.round(raw.gph * 10) / 10.0 };
    } else {
        var ac = (sel.type === "builtin") ? sel.ac : perfBuiltinByIcao(sel.ac.icao) || PERF_AIRCRAFT[1];
        r = perfCruise(ac, alt, power);
    }

    var fuel = sel.usableFuel || 0;
    var endurance = (r.gph > 0) ? (fuel / r.gph) : 0;
    var range = r.ktas * endurance * 0.9;

    document.getElementById("perf_cr_ktas").textContent = Math.round(r.ktas) + " kt";
    document.getElementById("perf_cr_gph").textContent = r.gph.toFixed(1) + " gph";
    document.getElementById("perf_cr_endurance").textContent = endurance.toFixed(1) + " hr";
    document.getElementById("perf_cr_range").textContent = Math.round(range) + " nm";
    var daEl = document.getElementById("perf_cr_da");
    if (daEl) daEl.textContent = Math.round(perfDensityAltitudeFromIsaDeviation(alt, isa)) + " ft";
}

// ------------------------------------------------------------------
// My Aircraft: template extraction, editor, save/load/delete
// ------------------------------------------------------------------

var perfEdTakeoff = [];
var perfEdLanding = [];
var perfEdCruise = [];

function perfSelectIndices(length, count) {
    if (length <= count) {
        var all = [];
        for (var i = 0; i < length; i++) all.push(i);
        return all;
    }
    var idx = [];
    for (var j = 0; j < count; j++) {
        var v = Math.round(j * (length - 1) / (count - 1));
        if (idx.indexOf(v) === -1) idx.push(v);
    }
    idx.sort(function (a, b) { return a - b; });
    return idx;
}

function perfExtractTL(rollTable, over50Table, maxWeight) {
    var alts = rollTable.pa, temps = rollTable.temps;
    var ais = perfSelectIndices(alts.length, 4);
    var tis = perfSelectIndices(temps.length, 3);
    var out = [];
    for (var a = 0; a < ais.length; a++) {
        for (var t = 0; t < tis.length; t++) {
            out.push({
                altitude: alts[ais[a]], temp: temps[tis[t]], weight: maxWeight,
                groundRoll: rollTable.values[ais[a]][tis[t]], over50ft: over50Table.values[ais[a]][tis[t]]
            });
        }
    }
    return out;
}

function perfExtractCruise(cruiseArr) {
    var alts = [];
    for (var i = 0; i < cruiseArr.length; i++) if (alts.indexOf(cruiseArr[i].altitude) === -1) alts.push(cruiseArr[i].altitude);
    alts.sort(function (a, b) { return a - b; });
    var selAlts = (alts.length <= 4) ? alts : perfSelectIndices(alts.length, 4).map(function (k) { return alts[k]; });
    var out = [];
    for (var s = 0; s < selAlts.length; s++) {
        var atAlt = [];
        for (var j = 0; j < cruiseArr.length; j++) if (cruiseArr[j].altitude === selAlts[s]) atAlt.push(cruiseArr[j]);
        atAlt.sort(function (a, b) { return b.percentPower - a.percentPower; });
        var sel = (atAlt.length <= 3) ? atAlt : perfSelectIndices(atAlt.length, 3).map(function (k) { return atAlt[k]; });
        for (var e = 0; e < sel.length; e++) {
            out.push({ altitude: sel[e].altitude, temp: 0, powerPercent: sel[e].percentPower, ktas: sel[e].ktas, gph: sel[e].gph });
        }
    }
    return out;
}

// Fill the editor from a built-in template index.
function perfLoadEditorFromTemplate(idx) {
    if (isNaN(idx) || idx < 0 || idx >= PERF_AIRCRAFT.length) idx = 1;
    var t = PERF_AIRCRAFT[idx];

    var nameEl = document.getElementById("perf_ed_name");
    if (nameEl) nameEl.value = perfLoadedName();
    document.getElementById("perf_ed_icao").value = perfLoadedType() || t.icao;
    document.getElementById("perf_ed_maxgross").value = Math.round(t.maxGross);
    document.getElementById("perf_ed_fuel").value = t.usableFuel;
    document.getElementById("perf_ed_empty").value = Math.round(t.emptyWeight);
    document.getElementById("perf_ed_to_hw").value = "1.5";
    document.getElementById("perf_ed_to_tw").value = "10";
    document.getElementById("perf_ed_to_sf").value = "15";
    document.getElementById("perf_ed_ld_hw").value = "1.5";
    document.getElementById("perf_ed_ld_tw").value = "10";
    document.getElementById("perf_ed_ld_sf").value = "20";

    perfEdTakeoff = perfExtractTL(t.takeoffRoll, t.takeoff50, t.maxGross);
    perfEdLanding = perfExtractTL(t.landingRoll, t.landing50, t.maxGross);
    perfEdCruise = perfExtractCruise(t.cruise);

    perfRenderEditor();
}

// "Load template" button: use the template picked in the dropdown.
function perfNewFromTemplate() {
    var tsel = document.getElementById("perf_template");
    var idx = tsel ? parseInt(tsel.value) : 1;
    perfLoadEditorFromTemplate(idx);
    toastr.success("Loaded template. Edit values, then Save to Aircraft.");
}

// Seed the editor from a built-in whose ICAO matches the aircraft type
// (used when an aircraft has no perf data yet).
function perfLoadEditorFromTemplateForType(type) {
    var idx = 1;
    for (var i = 0; i < PERF_AIRCRAFT.length; i++) {
        if (type && PERF_AIRCRAFT[i].icao.toLowerCase() === type.toLowerCase()) { idx = i; break; }
    }
    perfLoadEditorFromTemplate(idx);
}

// Fill the editor from an existing per-aircraft perf profile.
function perfLoadEditorFromProfile(p) {
    if (!p) return;
    document.getElementById("perf_ed_name").value = p.name || perfLoadedName();
    document.getElementById("perf_ed_icao").value = p.icao || perfLoadedType();
    document.getElementById("perf_ed_maxgross").value = Math.round(p.maxGross || 0);
    document.getElementById("perf_ed_fuel").value = p.usableFuel || 0;
    document.getElementById("perf_ed_empty").value = Math.round(p.emptyWeight || 0);
    var to = p.takeoff || {}, ld = p.landing || {};
    document.getElementById("perf_ed_to_hw").value = perfDefault(to.headwindPct, 1.5);
    document.getElementById("perf_ed_to_tw").value = perfDefault(to.tailwindPct, 10);
    document.getElementById("perf_ed_to_sf").value = perfDefault(to.softFieldPct, 15);
    document.getElementById("perf_ed_ld_hw").value = perfDefault(ld.headwindPct, 1.5);
    document.getElementById("perf_ed_ld_tw").value = perfDefault(ld.tailwindPct, 10);
    document.getElementById("perf_ed_ld_sf").value = perfDefault(ld.softFieldPct, 20);

    perfEdTakeoff = (to.entries || []).map(function (e) { return {altitude:e.altitude,temp:e.temp,weight:e.weight,groundRoll:e.groundRoll,over50ft:e.over50ft}; });
    perfEdLanding = (ld.entries || []).map(function (e) { return {altitude:e.altitude,temp:e.temp,weight:e.weight,groundRoll:e.groundRoll,over50ft:e.over50ft}; });
    perfEdCruise = (p.cruise || []).map(function (e) { return {altitude:e.altitude,temp:e.temp,powerPercent:e.powerPercent,ktas:e.ktas,gph:e.gph}; });

    perfRenderEditor();
}

var PERF_TL_COLS = ["altitude", "temp", "weight", "groundRoll", "over50ft"];
var PERF_CR_COLS = ["altitude", "temp", "powerPercent", "ktas", "gph"];

function perfRenderRows(tableId, prefix, cols, headers, arr) {
    var t = document.getElementById(tableId);
    if (!t) return;
    var html = "<tr>";
    for (var h = 0; h < headers.length; h++) html += "<th>" + headers[h] + "</th>";
    html += "<th></th></tr>";
    for (var r = 0; r < arr.length; r++) {
        html += "<tr>";
        for (var c = 0; c < cols.length; c++) {
            var val = arr[r][cols[c]];
            html += '<td><input style="width:60px;" type="number" id="' + prefix + "_" + r + "_" + cols[c] + '" value="' + val + '"></td>';
        }
        html += '<td><button class="btn" onclick="perfDelRow(\'' + prefix + '\',' + r + ')">X</button></td>';
        html += "</tr>";
    }
    t.innerHTML = html;
}

function perfRenderEditor() {
    perfRenderRows("perf_ed_to_table", "pedto", PERF_TL_COLS, ["PA", "\u00B0C", "Wt", "Roll", "50ft"], perfEdTakeoff);
    perfRenderRows("perf_ed_ld_table", "pedld", PERF_TL_COLS, ["PA", "\u00B0C", "Wt", "Roll", "50ft"], perfEdLanding);
    perfRenderRows("perf_ed_cr_table", "pedcr", PERF_CR_COLS, ["Alt", "ISA\u00B0", "%Pwr", "KTAS", "GPH"], perfEdCruise);
}

function perfArrFor(prefix) {
    if (prefix === "pedto") return perfEdTakeoff;
    if (prefix === "pedld") return perfEdLanding;
    return perfEdCruise;
}

function perfColsFor(prefix) {
    return (prefix === "pedcr") ? PERF_CR_COLS : PERF_TL_COLS;
}

// Read current input values back into the JS arrays.
function perfSyncEditor() {
    var groups = [["pedto", perfEdTakeoff, PERF_TL_COLS], ["pedld", perfEdLanding, PERF_TL_COLS], ["pedcr", perfEdCruise, PERF_CR_COLS]];
    for (var g = 0; g < groups.length; g++) {
        var prefix = groups[g][0], arr = groups[g][1], cols = groups[g][2];
        for (var r = 0; r < arr.length; r++) {
            for (var c = 0; c < cols.length; c++) {
                var el = document.getElementById(prefix + "_" + r + "_" + cols[c]);
                if (el) { var v = parseFloat(el.value); arr[r][cols[c]] = isNaN(v) ? 0 : v; }
            }
        }
    }
}

function perfAddRow(prefix) {
    perfSyncEditor();
    var arr = perfArrFor(prefix);
    if (arr.length > 0) {
        var last = arr[arr.length - 1];
        var copy = {};
        var cols = perfColsFor(prefix);
        for (var c = 0; c < cols.length; c++) copy[cols[c]] = last[cols[c]];
        arr.push(copy);
    } else if (prefix === "pedcr") {
        arr.push({ altitude: 8000, temp: 0, powerPercent: 65, ktas: 110, gph: 8.5 });
    } else {
        arr.push({ altitude: 0, temp: 15, weight: 2400, groundRoll: 900, over50ft: 1500 });
    }
    perfRenderEditor();
}

function perfDelRow(prefix, index) {
    perfSyncEditor();
    var arr = perfArrFor(prefix);
    if (arr.length <= 1) { toastr.error("At least one row is required"); return; }
    arr.splice(index, 1);
    perfRenderEditor();
}

function perfBuildProfileJson() {
    perfSyncEditor();
    var name = document.getElementById("perf_ed_name").value;
    if (!name) { toastr.error("Enter an aircraft name"); return null; }
    var profile = {
        name: name,
        icao: document.getElementById("perf_ed_icao").value,
        maxGross: perfNum("perf_ed_maxgross", 2400),
        usableFuel: perfNum("perf_ed_fuel", 48),
        emptyWeight: perfNum("perf_ed_empty", 1500),
        takeoff: {
            entries: perfEdTakeoff,
            headwindPct: perfNum("perf_ed_to_hw", 1.5),
            tailwindPct: perfNum("perf_ed_to_tw", 10),
            softFieldPct: perfNum("perf_ed_to_sf", 15)
        },
        landing: {
            entries: perfEdLanding,
            headwindPct: perfNum("perf_ed_ld_hw", 1.5),
            tailwindPct: perfNum("perf_ed_ld_tw", 10),
            softFieldPct: perfNum("perf_ed_ld_sf", 20)
        },
        cruise: perfEdCruise
    };
    return JSON.stringify(profile);
}

// Save button: apply the edited perf to the loaded aircraft, then persist
// the whole aircraft (profile + W&B + perf) to the database.
function perfSaveProfile() {
    var json = perfBuildProfileJson();
    if (json === null) return;
    try { perfAircraftProfile = JSON.parse(json); } catch (e) { perfAircraftProfile = null; }
    perfRefresh();
    if (typeof ac_save_ac_add === "function") {
        // Persists the aircraft record, which now embeds this perf.
        ac_save_ac_add();
    } else {
        toastr.success("Performance applied to aircraft");
    }
}

function perfInit() {
    if (!document.getElementById("perf_editor")) return;
    perfPopulateTemplates();
    // Start the editor from a sensible default until an aircraft is loaded.
    perfLoadEditorFromTemplateForType(perfLoadedType());
    perfRefresh();
}
